import "github.com/openmeterio/openmeter/pkg/framework/clickhouseotel"

conn, err := clickhouseotel.NewClickHouseTracer(clickhouseotel.ClickHouseTracerConfig{
    Tracer: tracer,
    Conn:   rawConn,
})

import (
    "github.com/openmeterio/openmeter/pkg/framework/commonhttp"
    "github.com/openmeterio/openmeter/pkg/models"
)

err := models.NewValidationIssue(
    models.ErrorCode("invalid_field"),
    "field x is required",
    commonhttp.WithHTTPStatusCodeAttribute(http.StatusUnprocessableEntity),
)
// In the handler's error encoder chain:
commonhttp.HandleIssueIfHTTPStatusKnown(ctx, err, w) // returns true, writes 422

import (
    "github.com/openmeterio/openmeter/pkg/framework/lockr"
    "github.com/openmeterio/openmeter/pkg/framework/transaction"
)

key, err := lockr.NewKey("billing", customerID)
if err != nil { return err }

return transaction.RunWithNoValue(ctx, txCreator, func(ctx context.Context) error {
    if err := locker.LockForTX(ctx, key); err != nil {
        return err
    }
    // safe to mutate customer billing state
    return doWork(ctx)
})
